class Solution {
public:
    long long validSubstringCount(string word1, string word2) {
        int count = 0;
        for (int i = 0; i < word1.length(); i++) {
            if (word2.substr(0, word1.length() - i) == word1.substr(i)) {
                count++;
            }
        }
        return count;
    }
};
```

